const container = document.getElementById("bikeContainer");
const brandContainer = document.getElementById("brandContainer");

const brandLogos = {
    "Yamaha": "data:image/png;base64,",
    "Royal Enfield": "data:image/jpeg;base64,",
    "Kawasaki": "data:image/png;base64,",
    "Zero": "data:image/jpeg;base64,",
    "Honda": "data:image/jpeg;base64,",
    "Ducati": "data:image/jpeg;base64,",
    "KTM": "data:image/png;base64,",
    "BMW": "data:image/jpeg;base64,",
    "Harley-Davidson": "data:image/png;base64,",
    "Aprilia": "data:image/png;base64,",
    "MV Agusta": "data:image/png;base64,",
    "Triumph": "data:image/png;base64,",
    "Suzuki": "data:image/png;base64,",
    "Indian": "https://upload.wikimedia.org/wikipedia/commons/5/5a/Indian_Motorcycle_Logo.svg",
    "LiveWire": "https://upload.wikimedia.org/wikipedia/commons/d/dc/LiveWire_logo_%282021%29.svg",
    "Energica": "https://upload.wikimedia.org/wikipedia/commons/0/07/Energica_logo.svg",
    "TVS": "https://upload.wikimedia.org/wikipedia/commons/3/30/TVS_Motor_Company_Logo.svg",
    "Bajaj": "https://upload.wikimedia.org/wikipedia/commons/0/0b/Bajaj_Auto_Logo.svg"
};

function renderBrands() {
    brandContainer.innerHTML = "";
    const brands = [...new Set(bikes.map(b => b.brand))];
    brands.forEach(brand => {
        const btn = document.createElement("button");
        btn.classList.add("brand-logo-btn");
        btn.onclick = () => filterBrand(brand);

        if (brandLogos[brand]) {
            btn.innerHTML = `<img src="${brandLogos[brand]}" alt="${brand}" class="brand-logo-img">`;
        } else {
            btn.textContent = brand; // fallback
        }

        brandContainer.appendChild(btn);
    });
}


function displayBikes(bikesToShow) {
    container.innerHTML = "";

    if (!bikesToShow || bikesToShow.length === 0) {
        const message = document.createElement("h2");
        message.textContent = " Bikes Not Found";
        message.style.color = "red";
        message.style.textAlign = "center";
        message.style.marginTop = "20px";
        container.appendChild(message);
        return;
    }

    bikesToShow.forEach((bike, index) => {
        const card = document.createElement("div");
        card.classList.add("bike-card");
        card.style.animationDelay = `${index * 0.05}s`;

        card.onclick = () => {
            window.location.href = `bike-details.html?model=${encodeURIComponent(bike.model)}`;
        };

        card.innerHTML = `
            <div class="card-img-wrapper">
                <img src="${bike.image}" alt="${bike.model}" class="bike-img">
                <span class="bike-type-badge">${bike.type}</span>
            </div>
            <div class="card-content">
                <h3>${bike.brand} ${bike.model}</h3>
                <div class="bike-specs">
                    <span class="spec-badge">📅 ${bike.year}</span>
                    <span class="spec-badge">⚙️ ${bike.cc}cc</span>
                    <span class="spec-badge">💰 ${bike.price}</span>
                </div>
            </div>
        `;

        container.appendChild(card);
    });
}

let currentCategory = "All";
let currentBrand = "All";

function filterCategory(category) {
    currentCategory = category;
    currentBrand = "All"; // Reset brand filter
    applyAdvancedFilters();
}

function filterBrand(brand) {
    currentBrand = brand;
    currentCategory = "All"; // Reset category filter
    applyAdvancedFilters();
}

// Filter menu toggle
const fabFilterBtn = document.getElementById("fabFilterBtn");
const filterMenu = document.getElementById("filterMenu");
const closeFilterBtn = document.getElementById("closeFilterBtn");

if (fabFilterBtn && filterMenu && closeFilterBtn) {
    fabFilterBtn.addEventListener("click", () => {
        filterMenu.classList.toggle("active");
    });

    closeFilterBtn.addEventListener("click", () => {
        filterMenu.classList.remove("active");
        applyAdvancedFilters();
    });
}

const ccFilter = document.getElementById("ccFilter");
const yearFilter = document.getElementById("yearFilter");
const priceFilter = document.getElementById("priceFilter");
const searchInput = document.getElementById("searchInput");

if (ccFilter) ccFilter.addEventListener("change", applyAdvancedFilters);
if (yearFilter) yearFilter.addEventListener("change", applyAdvancedFilters);
if (priceFilter) priceFilter.addEventListener("change", applyAdvancedFilters);
if (searchInput) searchInput.addEventListener("input", applyAdvancedFilters);

function applyAdvancedFilters() {
    let filtered = bikes;

    // Category match
    if (currentCategory !== "All") {
        filtered = filtered.filter(b => b.type === currentCategory);
    }

    // Brand match
    if (currentBrand !== "All") {
        filtered = filtered.filter(b => b.brand === currentBrand);
    }

    // Search text
    if (searchInput) {
        const searchVal = searchInput.value.toLowerCase();
        if (searchVal) {
            filtered = filtered.filter(bike =>
                bike.brand.toLowerCase().includes(searchVal) ||
                bike.model.toLowerCase().includes(searchVal)
            );
        }
    }

    // CC filter
    if (ccFilter) {
        const ccVal = ccFilter.value;
        if (ccVal === "under500") filtered = filtered.filter(b => b.cc < 500);
        else if (ccVal === "500to1000") filtered = filtered.filter(b => b.cc >= 500 && b.cc <= 1000);
        else if (ccVal === "over1000") filtered = filtered.filter(b => b.cc > 1000);
    }

    // Year filter
    if (yearFilter) {
        const yearVal = yearFilter.value;
        if (yearVal === "before2015") filtered = filtered.filter(b => b.year < 2015);
        else if (yearVal === "2015to2020") filtered = filtered.filter(b => b.year >= 2015 && b.year <= 2020);
        else if (yearVal === "after2020") filtered = filtered.filter(b => b.year > 2020);
    }

    // Price filter
    if (priceFilter) {
        const priceVal = priceFilter.value;
        if (priceVal !== "all") {
            filtered = filtered.filter(b => {
                // Parse price safely, removing all non-digits
                let numPrice = 0;
                if (typeof b.price === 'string') {
                    numPrice = parseInt(b.price.replace(/[^\d]/g, ''), 10);
                } else if (typeof b.price === 'number') {
                    numPrice = b.price;
                }

                if (isNaN(numPrice)) return true; // Fallback if parse fails

                if (priceVal === "under5L") return numPrice < 500000;
                if (priceVal === "5Lto15L") return numPrice >= 500000 && numPrice <= 1500000;
                if (priceVal === "over15L") return numPrice > 1500000;
                return true;
            });
        }
    }

    displayBikes(filtered);
}

displayBikes(bikes);
renderBrands();


